// Para que sirve: Utilidades puras de datos para el contexto de productos.
//   cleanOrphanFavorites sincroniza la lista de favoritos cuando se elimina un producto
//   del catálogo para evitar IDs huérfanos en localStorage.
// Flujo principal: ProductContext.deleteProduct → cleanOrphanFavorites → actualiza localStorage.
// Dónde tocar cambios: aquí si se añaden más operaciones de higiene de datos de productos.

/**
 * Removes favorite IDs that no longer exist in the product catalog.
 * @param {Array<number|string>} favorites
 * @param {Array<{ id: number }>} products
 * @returns {Array<number|string>}
 */
export function cleanOrphanFavorites(favorites, products) {
  if (!Array.isArray(favorites) || !Array.isArray(products)) {
    return [];
  }

  const productIds = new Set(products.map((p) => p?.id).filter((id) => id !== undefined));
  return favorites.filter((favId) => productIds.has(favId));
}
